class RacingGame {
    constructor() {
        this.player = {
            x: 400,
            y: 300,
            speed: 0,
            maxSpeed: 5,
            acceleration: 0.1,
            deceleration: 0.05,
            rotation: 0,
            rotationSpeed: 0.05
        };
        
        this.keys = {};
        this.lastTime = 0;
        this.gameLoop = null;
        this.obstacles = [];
        this.score = 0;
        this.gameRunning = false;
        
        this.init();
    }
    
    init() {
        this.setupEventListeners();
        this.createObstacles();
        this.startGame();
    }
    
    setupEventListeners() {
        document.addEventListener('keydown', (e) => {
            this.keys[e.key] = true;
        });
        
        document.addEventListener('keyup', (e) => {
            this.keys[e.key] = false;
        });
    }
    
    createObstacles() {
        for (let i = 0; i < 10; i++) {
            this.obstacles.push({
                x: Math.random() * 800,
                y: Math.random() * 600,
                width: 20,
                height: 20
            });
        }
    }
    
    startGame() {
        this.gameRunning = true;
        this.lastTime = performance.now();
        this.gameLoop = setInterval(() => this.update(), 16);
    }
    
    update() {
        if (!this.gameRunning) return;
        
        const currentTime = performance.now();
        const deltaTime = Math.min(100, currentTime - this.lastTime) / 1000;
        this.lastTime = currentTime;
        
        this.handleInput(deltaTime);
        this.updatePlayer(deltaTime);
        this.checkCollisions();
        this.updateScore();
        this.render();
    }
    
    handleInput(deltaTime) {
        if (this.keys['ArrowUp'] || this.keys['w']) {
            this.player.speed = Math.min(this.player.speed + this.player.acceleration, this.player.maxSpeed);
        } else if (this.keys['ArrowDown'] || this.keys['s']) {
            this.player.speed = Math.max(this.player.speed - this.player.acceleration, -this.player.maxSpeed/2);
        } else {
            if (this.player.speed > 0) {
                this.player.speed = Math.max(this.player.speed - this.player.deceleration, 0);
            } else if (this.player.speed < 0) {
                this.player.speed = Math.min(this.player.speed + this.player.deceleration, 0);
            }
        }
        
        if (this.keys['ArrowLeft'] || this.keys['a']) {
            this.player.rotation -= this.player.rotationSpeed * deltaTime;
        }
        
        if (this.keys['ArrowRight'] || this.keys['d']) {
            this.player.rotation += this.player.rotationSpeed * deltaTime;
        }
    }
    
    updatePlayer(deltaTime) {
        const moveX = Math.cos(this.player.rotation) * this.player.speed * deltaTime;
        const moveY = Math.sin(this.player.rotation) * this.player.speed * deltaTime;
        
        this.player.x += moveX;
        this.player.y += moveY;
        
        // Boundary checks
        this.player.x = Math.max(0, Math.min(800, this.player.x));
        this.player.y = Math.max(0, Math.min(600, this.player.y));
    }
    
    checkCollisions() {
        for (let obstacle of this.obstacles) {
            const dx = this.player.x - obstacle.x;
            const dy = this.player.y - obstacle.y;
            const distance = Math.sqrt(dx * dx + dy * dy);
            
            if (distance < 25) {
                this.gameRunning = false;
                clearInterval(this.gameLoop);
                alert('Game Over! Your score: ' + this.score);
                return;
            }
        }
    }
    
    updateScore() {
        this.score += Math.abs(this.player.speed) * 0.1;
    }
    
    render() {
        const canvas = document.getElementById('gameCanvas');
        const ctx = canvas.getContext('2d');
        
        // Clear canvas
        ctx.clearRect(0, 0, 800, 600);
        
        // Draw player
        ctx.save();
        ctx.translate(this.player.x, this.player.y);
        ctx.rotate(this.player.rotation);
        ctx.fillStyle = '#00ff00';
        ctx.fillRect(-10, -5, 20, 10);
        ctx.restore();
        
        // Draw obstacles
        ctx.fillStyle = '#ff0000';
        for (let obstacle of this.obstacles) {
            ctx.fillRect(obstacle.x, obstacle.y, obstacle.width, obstacle.height);
        }
        
        // Draw score
        ctx.fillStyle = '#000000';
        ctx.font = '20px Arial';
        ctx.fillText('Score: ' + Math.floor(this.score), 10, 30);
    }
}

// Security validation function
function validateInput(input) {
    const allowedKeys = ['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight', 'w', 'a', 's', 'd'];
    return allowedKeys.includes(input);
}

// Initialize game
window.addEventListener('load', () => {
    const game = new RacingGame();
    
    // Security: Validate input before processing
    document.addEventListener('keydown', (e) => {
        if (!validateInput(e.key)) {
            e.preventDefault();
            return false;
        }
    });
});